import { test, expect } from '@playwright/test';

const BASE_URL = process.env.BASE_URL ?? 'http://localhost:3000';

test.describe('Admin Dashboard — hard-dashboard', () => {
  test.afterEach(async ({ page }, testInfo) => {
    if (testInfo.status !== testInfo.expectedStatus) {
      const name = testInfo.title.replace(/[^a-z0-9]/gi, '-');
      await page.screenshot({ path: `evidence/${name}-FAIL.png`, fullPage: true });
    }
  });

  test.describe.configure({ mode: 'serial' });

  test('DASH-01 — Data table renders with correct sort controls', async ({ page }) => {
    // Step 1: Navigate to admin dashboard
    await page.goto(`${BASE_URL}/admin/dashboard`);

    // Step 2: Wait for table to be visible
    await page.locator('#users-table').waitFor({ state: 'visible' });

    // [VERIFY] Confirm Name column sort button has aria-sort="ascending"
    const nameSortBtn = page.locator('[data-sort-col="name"]');
    await expect(nameSortBtn).toHaveAttribute('aria-sort', 'ascending');

    // [VERIFY] Confirm other sort buttons have aria-sort="none"
    await expect(page.locator('[data-sort-col="email"]')).toHaveAttribute('aria-sort', 'none');

    await page.screenshot({ path: 'evidence/DASH-01-table-render.png' });
  });

  test('DASH-08 — Invite modal opens with focus on first field', async ({ page }) => {
    // Step 1: Navigate as admin
    await page.goto(`${BASE_URL}/admin/dashboard`);

    // Step 2: Click Invite User button
    await page.getByRole('button', { name: 'Invite new user' }).click();

    // [VERIFY] Confirm dialog is open
    const modal = page.locator('#invite-modal');
    await expect(modal).toBeVisible();

    // [VERIFY] Confirm focus is on the email input
    await expect(page.locator('#invite-email')).toBeFocused();

    await page.screenshot({ path: 'evidence/DASH-08-modal-focus.png' });
  });

  test('DASH-14 — Skip navigation link reaches main content', async ({ page }) => {
    // Step 1: Navigate to dashboard
    await page.goto(`${BASE_URL}/admin/dashboard`);

    // Step 2: Tab once to reach skip link
    await page.keyboard.press('Tab');

    // [VERIFY] Confirm skip link is focused and visible
    const skipLink = page.getByRole('link', { name: 'Skip to main content' });
    await expect(skipLink).toBeFocused();

    // Step 3: Activate skip link
    await page.keyboard.press('Enter');

    // [VERIFY] Confirm focus moves to main content
    await expect(page.locator('#main-content')).toBeFocused();

    await page.screenshot({ path: 'evidence/DASH-14-skip-nav.png' });
  });
});
